26: func VerbMatches(rule *rbacv1.PolicyRule, requestedVerb string) bool {
27: 	for _, ruleVerb := range rule.Verbs {
28: 		if ruleVerb == rbacv1.VerbAll {
29: 			return true
30: 		}
31: 		if ruleVerb == requestedVerb {
32: 			return true
33: 		}
34: 	}
35: 
36: 	return false
37: }
